// innerHTML -- UNSAFE with user-controlled data (XSS)
// Only use for trusted, static HTML you control
el.innerHTML = '<strong>Bold text</strong>'; // parses and renders HTML

// innerText -- like textContent but aware of CSS (slower, avoid in loops)
el.innerText = 'visible text';

const link = document.querySelector<HTMLAnchorElement>('a.logo')!;

// Generic attribute methods
