card.dataset.userId = '42';  // sets data-user-id="42"
const id = card.dataset.userId; // '42'

const bar = document.querySelector<HTMLElement>('.progress-bar')!;

// Camel-cased JS property names map to CSS hyphenated names
bar.style.width          = `${percent}%`;  // computed value -- class can't do this
bar.style.backgroundColor = '#3b82f6';
bar.style.transform       = `translateX(${offset}px)`;

// Remove an inline style (fall back to stylesheet value)
bar.style.removeProperty('background-color');

// Read computed style (what the browser actually renders)
const computed = getComputedStyle(bar);
console.log(computed.fontSize); // e.g. '16px'

// Create
const li = document.createElement('li');
li.className = 'menu-item';
li.textContent = 'New item';

// Insert
const ul = document.querySelector('ul.menu')!;
ul.append(li);              // insert at end (accepts strings and nodes)
ul.prepend(li);             // insert at start
ul.insertBefore(li, ul.firstElementChild); // before a specific child
li.insertAdjacentElement('afterend', anotherEl); // relative to li

// Remove
li.remove();                             // self-remove
ul.removeChild(ul.lastElementChild!);   // parent removes child

// Clone
const clone = li.cloneNode(true) as HTMLLIElement; // true = deep clone
