import { Renderer2, ElementRef, inject } from '@angular/core';

@Directive({ selector: '[appHighlight]' })
export class HighlightDirective {
  private el       = inject(ElementRef);
  private renderer = inject(Renderer2);

  highlight(color: string) {
    // Renderer2 works with SSR and web workers; nativeElement does not
    this.renderer.setStyle(this.el.nativeElement, 'background-color', color);
    this.renderer.addClass(this.el.nativeElement, 'highlighted');
  }

  clear() {
    this.renderer.removeStyle(this.el.nativeElement, 'background-color');
    this.renderer.removeClass(this.el.nativeElement, 'highlighted');
  }
}

