import { ComponentFixture, TestBed } from '@angular/core/testing';
import { By } from '@angular/platform-browser';

describe('HighlightDirective', () => {
  let fixture: ComponentFixture<TestHostComponent>;

  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [TestHostComponent, HighlightDirective],
    }).compileComponents();
    fixture = TestBed.createComponent(TestHostComponent);
    fixture.detectChanges();
  });

  it('adds highlighted class on hover', () => {
    const el = fixture.debugElement.query(By.directive(HighlightDirective));
    // Simulate DOM event
    el.triggerEventHandler('mouseenter', {});
    fixture.detectChanges();

    // Assert class was added to nativeElement
    expect(el.nativeElement.classList).toContain('highlighted');
  });

  it('removes class on mouseleave', () => {
    const el = fixture.debugElement.query(By.directive(HighlightDirective));
    el.triggerEventHandler('mouseenter', {});
    el.triggerEventHandler('mouseleave', {});
    fixture.detectChanges();

    expect(el.nativeElement.classList).not.toContain('highlighted');
  });
});
